    patterns = [r'([0-9,]+) stars', r'stars count of ([0-9,]+)', r'has a total of ([0-9,]+) stars', r'has garnered a total of ([0-9,]+) stars', r'has currently [0-9,]+ open issues, ([0-9,]+) stars']
